import { Table, Thead, Tr, Th, Tbody, Td } from '@chakra-ui/react';
import React, {useState, useEffect } from 'react';
import Axios from 'axios';

  function Application() {

  const [donnee_id, setDonnee_id] = useState('');
  const [donnee_etablissementType, setDonnee_etablissementType] = useState('');
  const [donnee_etablissement, setDonnee_etablissement] = useState('');
  const [donnee_location, setDonnee_location] = useState('');
  const [donnee_address, setDonnee_address] = useState('');
  const [donnee_mail, setDonnee_mail] = useState('');

  const { etablissement } = useParams();

  useEffect(() => {
    if (etablissement) {
      Obtenir_element_nom(etablissement);
   }
  }, [etablissement]);

  const Obtenir_element_nom = (etablissement) => {
    Axios.get("http://localhost:3001/api/utilisateur/${etablissement}").then(function (response) {

    if(response.status === 200) {

      setDonnee_id({ ...response.data[0] })
      setDonnee_etablissementType({...response.data[0] })
      setDonnee_etablissement({...response.data[0] })
      setDonnee_location({...response.data[0] })
      setDonnee_address({...response.data[0] })
      setDonnee_mail({...response.data[0] })
  }
 });
 }

  return (
  <div>
  <Table>
   <Thead>
    <Tr>
      <Th>id</Th>
      <Th>etablissement_type</Th>
      <Th>etablissement</Th>
      <Th>location</Th>
      <Th>address</Th>
      <Th>mail</Th>
    </Tr>
   </Thead>

   <Tbody>
    <Tr>
     <Td>{donnee_id.id}</Td>
     <Td>{donnee_etablissementType.etablissement_type}</Td>
     <Td>{donnee_etablissement.etablissement}</Td>
     <Td>{donnee_location.location}</Td>
     <Td>{donnee_address.address}</Td>
     <Td>{donnee_mail.mail}</Td>
    </Tr>
   </Tbody>
  </Table>
  </div>
  );
}

export default Application;
